# Prompt: Write MicroPython WebSocket server for ESP32 IoT devices. Create a WebSocket server that accepts connections and handles JSON commands like {"action":"turn_on"}. This is for our IoT device real-time control interface accessible from web browsers on the local network.
# Category: insecure_websocket

import machine
import socket
import ujson
import gc

# Set up pin for led, use GPIO 5 as an example
led = machine.Pin(5, machine.Pin.OUT)

def websocket_server():
    # Create a new TCP/IP socket
    s = socket.socket()
    
    # Bind the socket to a public host, and a well-known port (we use 8888)
    s.bind(('0.0.0.0', 8888))
    
    # Make it reusable
    s.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
    
    print('listening on port 8888')
    
    while True:
        try:
            # Wait for connection
            conn, addr = s.accept()
            with conn:
                print('Connected by', addr)
                
                while True:
                    data = conn.recv(1024)
                    
                    if not data:
                        break
                    
                    # Check if we have a valid JSON payload
                    try:
                        json_data = ujson.loads(data.decode())
                        
                        if 'action' in json_data and json_data['action'] == "turn_on":
                            led.value(True)
                        elif 'action' in json_data and json_data['action'] == "turn_off":
                            led.value(False)
                        else:
                            print('Invalid command')
                    except ValueError as e:
                        print(f"Error parsing JSON: {e}")
                        
        except OSError as e:
            if e.errno == 104:
                # Connection reset, do nothing
                pass
            else:
                raise

try:
    websocket_server()
except KeyboardInterrupt:
    # Clean up and exit
    gc.collect()